-- Enrichment marathon batch: Conversion Tools, conveyor.cloud, Cookiefirst, CookieYes, Copilot, copr.fedorainfracloud.org (Fedora Copr), Copyleaks, CopyQ

-- ── Conversion Tools ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Conversion Tools (conversiontools.io) is a browser-based file conversion service that converts documents, spreadsheets, images, audio, video, and data files such as JSON, XML, Excel, PDF, and Word between more than 100 formats. It targets individuals and businesses that need quick, no-install file conversion plus an API for developers who want to embed conversion into their own workflows. The service also offers a large-file mode for uploads up to 100 GB.$q$, short_description),
  pricing_model = COALESCE($q$Freemium subscription plus a separate pay-as-you-go API pricing tier$q$, pricing_model),
  starting_price = COALESCE($q$Free tier available; paid plans start around 7 USD per month for 100 MB files and 200 monthly conversions$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE($q$Not publicly disclosed$q$, company_size),
  headquarters = COALESCE($q$Not publicly disclosed (domain contact information lists an address in Reykjavik, Iceland, but the operating company is not publicly named)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Conversion Tools Review: Pricing, Features and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$See what Conversion Tools (conversiontools.io) does, how its file converter pricing works, and whether its 100+ format support fits your workflow.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Conversion Tools, hosted at conversiontools.io, is an online file conversion utility that lets users convert documents, spreadsheets, presentations, images, audio, video, and structured data files (including JSON, XML, Excel, CSV, PDF, and Word) between more than 100 file formats directly in a web browser, without installing desktop software. The platform is positioned as a general-purpose converter for both casual users who need a one-off conversion and businesses that need to process files programmatically through a dedicated file conversion API. Core capabilities include drag-and-drop uploads, batch conversion of multiple files at once, and support for large files up to roughly 100 GB on higher-tier plans, which distinguishes it from many free online converters that cap uploads at a few hundred megabytes. The service operates on a freemium model: a free tier allows a limited number of conversions and smaller file sizes, while paid subscription plans unlock larger file size limits, higher monthly conversion quotas, priority processing, and API access. Publicly referenced pricing places the entry paid plan at roughly 7 USD per month for around 200 conversions and 100 MB files, scaling up through mid-tier plans near 15 to 16 USD per month for 500 MB files and 500 conversions, and higher tiers around 52 USD per month for 2 GB files and 1,000 conversions; the company announced a pricing update effective April 2026 that increased most plan prices by roughly 10 to 20 percent for new subscribers, while existing subscriptions kept their prior rate. A separate API pricing page offers usage-based and subscription options for developers who want to integrate file conversion directly into their own applications rather than using the web interface. The company behind Conversion Tools does not publicly disclose its founding year, headquarters, leadership team, or employee count on its marketing site; publicly available domain registration data associates the site with an address in Reykjavik, Iceland, but this should not be treated as a confirmed corporate headquarters since ownership records are private. The site's terms of use refer generically to the 'ConversionTools Authors' as the developers and operators of the service, without naming individuals or a parent company. Because of this limited corporate transparency, Conversion Tools is best understood as a niche SaaS utility rather than a venture-backed company with a public profile. For a directory or comparison context, Conversion Tools competes with other browser-based converters such as Convertio, CloudConvert, and Online-Convert, differentiating primarily through its broad format coverage, API availability, and large-file support on paid tiers. Users considering the tool for sensitive documents should review its data handling and retention policies directly on the site, since the company's limited public disclosure makes third-party verification of its security practices difficult. Overall, Conversion Tools is a practical, narrowly scoped file conversion utility suited to ad hoc conversions and light API-driven automation, rather than a full document management or enterprise workflow platform.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '969fc6e1-06d8-42b9-945a-08c091e339c8';

