-- ── conveyor.cloud ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$conveyor.cloud is the home of Conveyor, a Visual Studio extension and standalone Windows tool made by Keyoti Inc. that gives developers local network and remote internet access to their IIS Express or ASP.NET development server through tunnelling, without changing project configuration. It is used mainly for cross-device testing, sharing a local build with collaborators, and receiving webhooks during development.$q$, short_description),
  pricing_model = COALESCE($q$Freemium with a paid per-developer annual license for Pro features$q$, pricing_model),
  starting_price = COALESCE($q$Free tier available; Pro license starts around 49 USD per developer per year$q$, starting_price),
  founded_year = COALESCE(2002, founded_year),
  company_size = COALESCE($q$Small (Keyoti Inc. is a small, privately held software company)$q$, company_size),
  headquarters = COALESCE($q$Comox, British Columbia, Canada$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$conveyor.cloud (Conveyor by Keyoti) Review, Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$What is Conveyor by Keyoti at conveyor.cloud? See how this Visual Studio tunnelling tool exposes IIS Express to devices and the internet, plus pricing.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$conveyor.cloud is the product site for Conveyor, a developer tool built by Keyoti Inc., a small Canadian software company founded in 2002 and based in Comox, British Columbia. Conveyor is distributed both as a Visual Studio extension and as a standalone Windows system-tray application, and its core purpose is to expose a local IIS Express or ASP.NET development server to other devices on the same network and, through tunnelling, to the broader internet, without requiring the developer to publish the project or change IIS Express configuration files. This solves a common web development problem: testing how a site or app behaves on a phone, tablet, or a colleague's machine when the site is still running only on the developer's own laptop. Once installed, Conveyor automatically generates a shareable URL that tunnels directly to the running ASP.NET application, which developers use for responsive design checks, cross-device QA, ad hoc demos, and receiving webhook callbacks from third-party services such as Twilio during local development, since webhook providers require a publicly reachable URL that a purely local server cannot provide. The standalone tool sits in the Windows system tray, can be configured to start automatically with Windows, and in its Pro tier supports custom port mappings and other advanced configuration not available in the free version. Conveyor offers a freemium pricing model: a free tier provides basic local network and limited internet tunnelling functionality, while a paid Pro upgrade unlocks features like custom subdomains and no connection time limits. Public pricing references place the Pro license at roughly 49 USD, licensed per developer per year, consistent with Keyoti's broader practice of selling per-developer annual licenses for its other components, such as its spell-checking and search engine libraries for .NET and Java. Because Conveyor is scoped specifically to Visual Studio and IIS Express or ASP.NET workflows, it functions as a narrower, more specialized alternative to general-purpose tunnelling tools such as ngrok or Cloudflare Tunnel; its main differentiation is tight, low-friction integration directly inside the Visual Studio IDE rather than a separate command-line tool. Keyoti Inc. itself is a long-running but small, privately held company that has focused since 2002 on developer productivity components rather than broad platform products, and it does not publicly disclose detailed revenue or headcount figures. Support for Conveyor is provided via email at support@conveyor.cloud and live chat on the product site. For a software directory entry, conveyor.cloud should be described precisely as Keyoti's Conveyor tunnelling and remote-testing tool for Visual Studio and IIS Express developers, distinct from unrelated same-named products such as Conveyor CI (a cloud-native CI/CD orchestration engine), ConveyorData (a data pipeline platform), and Conveyor.com (an AI-powered customer security review platform), none of which are affiliated with Keyoti's conveyor.cloud.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '4d396976-cc5c-4bf3-93a7-b18cb22dc1b2';

