-- ── Cookiefirst ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Cookiefirst is a consent management platform (CMP) that helps website owners scan for tracking cookies and scripts, display a customizable consent banner, and log visitor consent to comply with GDPR, ePrivacy, CCPA, LGPD, and other privacy laws. Founded in 2019 in Amsterdam, it was acquired by iubenda (a team.blue brand) in January 2025 and integrates with Google Consent Mode v2 and major CMS and tag manager platforms.$q$, short_description),
  pricing_model = COALESCE($q$Freemium subscription, billed per domain based on monthly page views and script count$q$, pricing_model),
  starting_price = COALESCE($q$Free plan available; paid plans start at 9 EUR per month (Basic)$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$Small (around 9 employees as an independent company before its 2025 acquisition by iubenda/team.blue, which employs 140+ across the group)$q$, company_size),
  headquarters = COALESCE($q$Amsterdam, Netherlands$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Dutch$q$, $q$German$q$, $q$French$q$, $q$Spanish$q$, $q$Italian$q$, $q$Portuguese$q$, $q$and 40+ additional languages for banner translations$q$]::text[],
  seo_title = COALESCE($q$Cookiefirst Review 2026: Pricing, Features and Compliance$q$, seo_title),
  seo_meta_description = COALESCE($q$Cookiefirst cookie consent platform: pricing, GDPR/CCPA compliance features, cookie scanning, Google Consent Mode v2 support, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Cookiefirst is a consent management platform (CMP) founded in 2019 by brothers Kees van den Bos and Tom van den Bos in Amsterdam, Netherlands, where the company (a registered brand of Digital Data Solutions BV) remains headquartered. In January 2025, Cookiefirst was acquired by iubenda, a European privacy compliance company that operates as a brand of the Belgium-based group team.blue; iubenda itself is based in Milan, Italy, and the combined group serves more than 100,000 customers across 100-plus countries. As an independent company, Cookiefirst had around 9 employees as of mid-2024, reflecting its position as a lean, focused SaaS product prior to being folded into iubenda's broader privacy compliance suite. The core product lets website owners generate a compliant cookie consent banner, run automated and periodic scans of a site's cookies and third-party tracking scripts, and maintain a searchable, exportable log of visitor consent choices for audit purposes. Cookiefirst supports compliance with GDPR and the ePrivacy Directive in the EU, CCPA in California, LGPD in Brazil, Quebec's Law 25, and PIPEDA in Canada, and it is a Google-certified Consent Management Platform partner, meaning it integrates directly with Google Consent Mode v2 and Microsoft's Universal Event Tracking (UET) Consent Mode so that advertising and analytics tags respect user consent choices automatically. The banner and accompanying auto-generated cookie policy can be translated into more than 44 languages, and the platform supports IAB TCF v2.2 for programmatic advertising compliance. Cookiefirst integrates with Google Tag Manager and offers plugins or native integrations for WordPress, Shopify, Magento, Drupal, and at least eight other CMS and e-commerce platforms, along with a documented API for custom implementations and role-based team permissions for larger organizations. Pricing follows a freemium, per-domain model gated primarily by monthly page views, with a soft cap of 250,000 page views per domain per month (allowing a 25 percent overage buffer across two consecutive months) before custom enterprise pricing is required. Published tiers include a Free plan limited to one third-party script and a single one-time scan and language; a Basic plan around 9 EUR per month (or roughly 99 EUR annually) that unlocks unlimited scripts, monthly automated scans, and multiple languages; and a Plus plan around 19 EUR per month adding priority support with a sub-24-hour response commitment; Enterprise pricing is custom for organizations with multiple domains or very high traffic. Annual billing includes one month free compared to paying monthly. The platform reports enterprise-grade customers including Vogue, Aegon, Hyundai, Elsevier, and InterContinental Hotels, and it runs a reseller program offering 30 percent commission for agencies and consultants who resell Cookiefirst to their clients. Competing directly with CookieYes, Cookiebot, and Osano in the consent management category, Cookiefirst differentiates through its straightforward per-domain pricing, broad language support for auto-generated policies, and its post-acquisition backing by iubenda's larger privacy compliance ecosystem, which now includes complementary products like privacy policy generators and terms-of-service tools.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'acd57c1b-0ec4-47eb-b5bb-a573a2b42662';

