-- ── CookieYes ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$CookieYes is a Google-certified consent management platform that automates cookie scanning, consent banners, and compliance logging for GDPR, CCPA, and other privacy laws, powering more than 1.5 million websites. It began in 2018 as the WordPress plugin Cookie Law Info and grew into a standalone CMP operated by CookieYes Limited, headquartered in Milton Keynes, England.$q$, short_description),
  pricing_model = COALESCE($q$Freemium subscription, billed per domain based on pages scanned and monthly page views$q$, pricing_model),
  starting_price = COALESCE($q$Free plan available; paid plans start at 10 USD per month per domain (Basic)$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE($q$Small to mid-size (exact headcount not publicly disclosed; company registered in the UK)$q$, company_size),
  headquarters = COALESCE($q$Milton Keynes, England, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$and auto-translated banner support for 30+ additional languages$q$]::text[],
  seo_title = COALESCE($q$CookieYes Review 2026: Pricing, Plans and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$CookieYes cookie consent platform review: pricing tiers, GDPR/CCPA compliance features, cookie scanning, and Google Consent Mode integration.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$CookieYes is a consent management platform (CMP) that automates cookie banner display, cookie scanning, and consent logging so website owners can comply with GDPR, ePrivacy, CCPA, and other global privacy regulations. The product traces back to 2018, when it launched as Cookie Law Info, a WordPress plugin; it later expanded into a standalone, platform-agnostic CMP and now operates under CookieYes Limited, a company registered in the United Kingdom (company number 13074037) and headquartered in Milton Keynes, England. CookieYes states that more than 1.5 million websites run its consent solution, spanning WordPress sites, Shopify stores, and custom-built websites, and it holds Google CMP certification, meaning it has been vetted for direct integration with Google Consent Mode V2 and the IAB Transparency and Consent Framework (TCF) v2.2/v2.3, both of which are used to control how advertising and analytics tags fire based on visitor consent. Core functionality includes an automated cookie scanner that periodically crawls a site to detect first- and third-party cookies and tracking scripts, a customizable and auto-translated consent banner, automatic blocking of non-essential cookies until consent is given, a consent log for audit and dispute purposes, and built-in legal policy generators for cookie policies and privacy notices. CookieYes uses a freemium, per-domain pricing model with four public tiers. The Free plan supports small blogs and personal sites with a 100-page scan limit and up to 5,000 monthly page views, offering basic banner customization, third-party cookie blocking, and Google Consent Mode and Do Not Track support at no cost. The Basic plan, priced around 10 USD per month per domain, raises the scan limit to 600 pages and page views to 100,000 per month (with overage billed at 0.30 USD per additional 1,000 views), and adds advanced customization such as multilingual auto-translated banners and custom CSS. The Pro plan, CookieYes's most popular tier at around 25 USD per month per domain, scans up to 4,000 pages, covers 300,000 monthly page views, and introduces geo-targeting (showing different consent flows by visitor location), monthly scheduled scanning, and full IAB TCF v2.2 and Google Consent Mode integration. The Ultimate plan, around 55 USD per month per domain, scans up to 8,000 pages, offers unlimited page views, weekly scheduled scanning, custom branding, the ability to remove CookieYes branding, scanning behind login walls, and IP whitelisting for the CookieYes scanner. All paid plans include a 14-day free trial with no charge until the trial ends, and annual billing includes roughly two months free compared to monthly billing; custom Enterprise pricing is available for large organizations with specialized needs. Because CookieYes started life as a widely adopted WordPress plugin, it retains especially deep WordPress integration alongside broader platform support, and it competes most directly with Cookiebot, Cookiefirst, and Osano in the consent management space, generally positioning itself on affordability at the entry tiers and straightforward per-domain scaling as traffic grows.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '400be7d4-2ff0-47ef-96d7-c97fc4aff7be';

