-- ── Copilot ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$This profile covers Copilot Money (copilot.money), a subscription personal finance app for tracking spending, budgets, investments, and net worth, founded in 2020 and headquartered in New York. It is distinguished here from Copilot.com (the agency client-portal platform, which rebranded to Assembly in 2025), GitHub Copilot, and Microsoft Copilot, none of which currently operate under the standalone Copilot brand name.$q$, short_description),
  pricing_model = COALESCE($q$Subscription (no free tier beyond a limited trial)$q$, pricing_model),
  starting_price = COALESCE($q$13 USD per month, or 95 USD billed annually$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$Small (approximately 33 employees)$q$, company_size),
  headquarters = COALESCE($q$New York, New York, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Copilot Money Review 2026: Pricing, Features and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Copilot Money app review: pricing, budgeting and net worth tracking features, iOS/Mac/web support, and how it compares to other finance apps.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$This entry covers Copilot Money, a personal finance and budgeting app available at copilot.money, and it is important to disambiguate this from several other products that also use the name Copilot. Copilot Money was founded in 2020 and is headquartered in New York City, with roughly 33 employees as of recent counts; it raised a Series A funding round of 6 million USD to build out its product. It was designed natively for Apple platforms from the start, launching first on iPhone, iPad, and Mac, and it added a limited web app in December 2025 that, as of early 2026, supports transaction filtering and basic metrics but is not a full replacement for the native mobile and desktop apps. The app connects to tens of thousands of financial institutions through account aggregation, with direct native integrations called out for services like Venmo, Apple Card, and Coinbase, and it uses AI-assisted categorization to automatically sort transactions, track spending trends over time, monitor investment account performance, and calculate net worth in one consolidated view. It operates on a pure subscription model with no persistent free tier: pricing is 13 USD per month or 95 USD per year (about 7.92 USD/month equivalent) on annual billing, with a one-month free trial available through the App Store and occasional extended trials via user referral codes. This entry deliberately does not cover three other prominent products that share the 'Copilot' name: (1) Copilot.com, a client portal, billing, e-signature, and CRM platform for service agencies, which rebranded to 'Assembly' in 2025 and therefore no longer operates under the standalone Copilot brand as of 2026; (2) GitHub Copilot, Microsoft/GitHub's AI pair-programming assistant integrated into code editors; and (3) Microsoft Copilot, the AI assistant embedded across Microsoft 365 and Windows. Because gappsy.com catalogs standalone named tools, and because Copilot.com's operating brand changed to Assembly, Copilot Money is the product that most closely and currently matches a standalone 'Copilot' listing distinct from the larger platform-embedded Copilot products from Microsoft and GitHub. Copilot Money's category peers include other premium budgeting and net-worth apps such as Monarch Money, YNAB (You Need A Budget), and Rocket Money, and it is frequently reviewed favorably by finance publications for its design quality and Apple-native experience, though its historical lack of an Android app and reliance on a paid-only model (versus some competitors' free tiers) are commonly cited drawbacks in third-party reviews. Prospective users evaluating Copilot Money should weigh its premium-only pricing and until-recently iOS/Mac-only availability against its polished interface, automated categorization accuracy, and investment-tracking depth compared to lower-cost or free budgeting alternatives.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '8949c855-f2b6-4ce4-b770-a4d05cadf7c6';

