-- ── copr.fedorainfracloud.org (Fedora Copr) ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Fedora Copr, hosted at copr.fedorainfracloud.org, is a free, community build system that lets anyone create and host custom RPM package repositories built from source RPMs, without needing them accepted into the official Fedora repositories. Sponsored by Red Hat and run within Fedora Project infrastructure, it uses the Mock chroot tool to build packages and is commonly used for third-party repositories, continuous integration, and mass rebuild testing.$q$, short_description),
  pricing_model = COALESCE($q$Free (open source, community/sponsored infrastructure, no paid tiers)$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE($q$Not applicable (community project sponsored by Red Hat within the Fedora Project; no independent company or employee count)$q$, company_size),
  headquarters = COALESCE($q$Not applicable (hosted on Fedora Project infrastructure; Red Hat, the primary sponsor, is headquartered in Raleigh, North Carolina, United States)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Fedora Copr (copr.fedorainfracloud.org): Free RPM Build System$q$, seo_title),
  seo_meta_description = COALESCE($q$What is Fedora Copr? A free, Red Hat-sponsored build system for hosting custom RPM package repositories, with mock-based chroot builds and API access.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Fedora Copr, accessible at copr.fedorainfracloud.org, is a free, lightweight build system that allows individual contributors and organizations to build software packages from source RPM files and automatically publish them as installable YUM/DNF repositories, without those packages needing to go through the review and inclusion process required for the official Fedora package repositories. It exists specifically to solve a common Linux packaging problem: a developer or project maintainer wants to distribute RPM packages for Fedora, RHEL, CentOS Stream, or other RPM-based distributions, but their software either does not yet qualify for or has not yet been submitted to the official distribution repositories. Copr fills that gap by providing free, self-service infrastructure where any user with a Fedora Account System (FAS) account can create a project, upload or point to a source RPM (SRPM), and have Copr build binary packages across multiple target chroots (combinations of distribution version and CPU architecture) automatically. Internally, Copr builds packages using Mock, the same chroot-based build environment manager that powers official Fedora and Koji builds, ensuring build isolation and reproducibility consistent with Fedora's own packaging standards; resulting repositories are cryptographically signed. Copr supports both standard chroots matching released Fedora, EPEL, and other distribution versions, and 'custom chroots,' which give project owners more manual control over the build environment for edge cases not covered by standard targets. The service is designed to scale to very large workloads: it can sustain mass rebuilds involving thousands of packages, a capability used within the Fedora community for tasks like rebuilding the entire package set against a proposed toolchain change or rebuilding language-ecosystem packages (such as Python PyPI packages or Ruby gems) as RPMs at scale. Common use cases beyond official Fedora packaging work include hosting third-party or 'copr' repositories that end users add manually to install software not available upstream, running continuous integration builds that need a real RPM output rather than just a compiled binary, and providing beta or nightly builds of a project ahead of formal release. Copr is sponsored by Red Hat and operates on servers deployed within Fedora Project infrastructure, working closely with the Fedora Infrastructure team, though Copr documentation notes it is not officially guaranteed-supported Fedora infrastructure in the same way core Fedora services are, meaning it should not be relied upon for absolutely mission-critical production package hosting without independent verification. Because it is a community and vendor-sponsored open source project rather than a company, Copr has no founding year, headquarters, pricing plans, or employee count in the traditional commercial sense; it is entirely free to use, and its source code is maintained publicly on GitHub under the fedora-copr organization, with a Python client library (python-copr) available for programmatic and automated interaction with the build service. For developers and system administrators, Copr functions similarly in spirit to other community package-hosting or CI-adjacent build services, but is uniquely tied to the RPM and Fedora/RHEL ecosystem rather than being distribution-agnostic.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '2c6b3848-19a4-4c49-b931-003ba838b9c9';

