-- ── Copyleaks ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Copyleaks is an AI-powered content integrity platform offering plagiarism detection, AI-generated text detection, source code plagiarism detection (Codeleaks), and AI image detection. Founded in 2015 by Alon Yamin and Yehonatan Bitton and headquartered in New York with an Israel-based team, it serves education, publishing, and enterprise customers through a web app, browser extension, API, and LMS integrations with Canvas, Moodle, and Blackboard.$q$, short_description),
  pricing_model = COALESCE($q$Freemium credit-based subscription, plus separate enterprise and API/model-integration pricing$q$, pricing_model),
  starting_price = COALESCE($q$Free plan available (~10 pages/month); paid individual plans start at 7.99 USD per month$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$Small to mid-size (reported at roughly 20 employees in 2024, growing to approximately 92 employees across three continents by early 2026)$q$, company_size),
  headquarters = COALESCE($q$New York, New York, United States (with a significant Tel Aviv, Israel operations base)$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$and AI/plagiarism detection support across 30+ languages$q$]::text[],
  seo_title = COALESCE($q$Copyleaks Review 2026: AI Detector and Plagiarism Checker Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Copyleaks review: AI content detection and plagiarism checker pricing, accuracy, LMS integrations, and enterprise API options for 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Copyleaks is a content authenticity and integrity platform that combines plagiarism detection with AI-generated content detection in a single product, founded in 2015 by software developers Alon Yamin and Yehonatan Bitton, who specialized in text analysis and machine learning. The company is headquartered in New York, New York, while maintaining a significant operational base in Tel Aviv, Israel, reflecting its origins as an Israeli startup; reported headcount has grown from around 20 employees in 2024 to approximately 92 employees across three continents by early 2026, and the company raised 7.75 million USD in funding in 2022 to expand its anti-plagiarism and AI detection capabilities. The core product scans submitted text and simultaneously checks it against a plagiarism database spanning the open web, academic publications, and internal/institutional repositories, while also running an AI content detector that claims over 99 percent accuracy and coverage of outputs from major language models including GPT, Gemini, and Claude, updated as new models are released; both plagiarism and AI-detection results appear together in a single combined report. Beyond text, Copyleaks offers Codeleaks, a specialized detector for identifying AI-generated or plagiarized source code, and an AI Image Detector that uses forensic image analysis and machine learning to flag AI-generated or manipulated images, presenting a visual overlay highlighting the specific regions most likely to be altered or synthetic. The platform integrates directly into learning management systems including Canvas, Moodle, and Blackboard, positioning it heavily toward educational institutions checking student submissions, alongside a Chrome browser extension, a web application, and a full API for developers who want to embed detection into their own products; it is also distributed via the Google Workspace Marketplace as an AI and Plagiarism Checker add-on. Pricing follows a freemium, credit-based subscription model. The free plan offers roughly 10 pages (about 2,500 words) of scanning per month, limited to two concurrent scans with lower processing priority, suitable only for occasional spot checks. Paid individual plans are priced separately or bundled: an AI Content Detector-only plan costs 7.99 USD per month for 1,200 credits (up to roughly 300,000 words) with two user seats and API access; a Plagiarism Detector-only plan costs 8.99 USD per month for the same credit allotment; and a combined AI and Plagiarism Detection plan costs 13.99 USD per month for both capabilities sharing the same credit pool. An annual option is also available, billed at 899.88 USD per year, which includes 25 user seats, making it more suitable for small teams or departments than the monthly individual plans. For large organizations, enterprise-grade model integration pricing starts at 4,500 USD per year, reflecting deeper API access and higher volume needs. Independent academic studies cited in third-party reviews show mixed accuracy results for AI detection generally across the industry, with Copyleaks specifically demonstrating around 93 percent sensitivity in detecting GPT-4-generated content in one study, while struggling more with text that has been manually edited or paraphrased after AI generation, a known limitation shared by most AI detectors. Copyleaks competes most directly with Turnitin, GPTZero, and Originality.ai in the combined plagiarism and AI-detection category, differentiating through its bundled multi-modal detection (text, code, and images) in one platform and its deep LMS integrations for academic institutions.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '6f6b7427-2a25-47de-809a-0cbf1f53a717';

