-- ── CopyQ ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$CopyQ is a free, open-source clipboard manager for Windows, macOS, and Linux that saves clipboard history and lets users search, edit, tag, and organize copied text, images, and files across tabs. Maintained by developer Lukas Holecek since 2009 under the GPLv3 license, it includes a scripting and command-line interface and can sync clipboard items across machines via a shared folder.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source (no paid tiers)$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2009, founded_year),
  company_size = COALESCE($q$Not applicable (independent open-source project maintained primarily by one developer with community contributors)$q$, company_size),
  headquarters = COALESCE($q$Not applicable (open-source project; maintainer based in the Czech Republic)$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$and numerous community-contributed UI translations$q$]::text[],
  seo_title = COALESCE($q$CopyQ Review 2026: Free Open-Source Clipboard Manager$q$, seo_title),
  seo_meta_description = COALESCE($q$CopyQ clipboard manager review: features, scripting, cross-device sync, and how it compares to other free clipboard tools for Windows, macOS, and Linux.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$CopyQ is a free, open-source clipboard manager originally created and still actively maintained by developer Lukas Holecek, with development history dating back to 2009 and the project accumulating over 9,000 stars on its GitHub repository. It runs on Windows 7 through 11, macOS 10.15 and later, and most major Linux distributions, presenting the same interface and feature set across all three platforms so users do not need to relearn the tool when switching operating systems. At its core, CopyQ monitors the system clipboard and automatically saves a history of everything copied, including plain text, rich text, images, and files, storing that history in a searchable, editable list organized into user-defined tabs. Users can attach notes to individual clipboard entries for extra context, apply tags to group and filter related items, edit clipboard content directly before pasting it again, and reorder items within the history. Beyond basic clipboard history, CopyQ includes a powerful command-line interface and a built-in scripting engine that let advanced users automate clipboard-related tasks, create custom commands triggered by clipboard content matching specific patterns, and build custom workflows, which is a key differentiator from simpler clipboard history tools that only offer a fixed list with no automation layer. CopyQ also supports syncing clipboard items across multiple machines by pointing the application at a shared folder, such as one managed by Dropbox, Google Drive, or a private network drive, allowing multi-device clipboard continuity without requiring a proprietary cloud service, a subscription, or a user account of any kind. The software is licensed under the GNU General Public License version 3 (GPLv3), which guarantees the source code will remain free, viewable, modifiable, and redistributable in perpetuity; there is no trial period, freemium tier, or paid upgrade path, as the entire feature set is available to every user at no cost. CopyQ is under active development, with recent major releases including version 13.0.0 in October 2025 and version 16.0.0 in May 2026, reflecting a steady release cadence for bug fixes, platform compatibility updates, and incremental feature additions. As an independent open-source project rather than a company, CopyQ has no headquarters, employee count, or founding company in the commercial sense; it is maintained primarily by Lukas Holecek along with community contributors submitting patches and translations through GitHub. In the clipboard manager category, CopyQ is most often compared to Ditto (Windows-only, also free and open source), Maccy and Paste (macOS-focused, with Paste being paid), and various built-in OS clipboard history tools; CopyQ differentiates itself through genuine cross-platform parity, its scripting and automation capabilities, and its no-cost, no-account model, making it a favorite among developers, power users, and anyone who copies and pastes frequently across multiple devices without wanting to rely on a cloud-synced commercial product.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f6cb1438-d516-463e-beaf-3bfbbafea48a';

